class Solution:
    def countOfAtoms(self, formula: str) -> str:
        stack = []
        curr_atom = {}
        for i in range(len(formula)):
            if formula[i].isalpha():
                atom = formula[i]
                if i + 1 < len(formula) and formula[i + 1].isdigit():
                    j = i + 1
                    while j < len(formula) and formula[j].isdigit():
                        j += 1
                    atom += formula[i + 1:j]
                    i = j - 1
                if atom in curr_atom:
                    curr_atom[atom] += 1
                else:
                    curr_atom[atom] = 1
            elif formula[i] == '(':
                stack.append(curr_atom)
                curr_atom = {}
            elif formula[i] == ')':
                prev_atom = stack.pop()
                for atom, count in curr_atom.items():
                    if atom in prev_atom:
                        prev_atom[atom] += count
                    else:
                        prev_atom[atom] = count
                curr_atom = prev_atom
        result = []
        for atom, count in curr_atom.items():
            if count > 1:
                result.append(f"{atom}{count}")
            else:
                result.append(atom)
        return ''.join(sorted(result))
